// Min-heap of (distance, node) pairs
priority_queue<pair<int,string>, vector<pair<int,string>>, greater<>> pq;
pq.push({3, "C"});
pq.push({1, "A"});
pq.push({2, "B"});

while (!pq.empty()) {
    auto [dist, node] = pq.top();
    pq.pop();
    cout << node << ":" << dist << " ";
}
// Output: A:1 B:2 C:3

