vector<int> topK(const vector<int>& nums, int k) {
    priority_queue<int, vector<int>, greater<int>> minPQ;
    for (int x : nums) {
        minPQ.push(x);
        if ((int)minPQ.size() > k) {
            minPQ.pop();
        }
    }
    vector<int> result;
    while (!minPQ.empty()) {
        result.push_back(minPQ.top());
        minPQ.pop();
    }
    return result;
}
// topK({3,1,5,12,2,11}, 3) -> {5, 11, 12}

